### 2. The Empirical Proof: Monotonic Graceful Degradation

This test mathematically proves that the expected recovered mutual information $I(p)$ is monotonically non-increasing with respect to the erasure fraction $p$, forming a staircase rather than a cliff.

```rust
#[cfg(test)]
mod proofs {
    use super::*;

    // Deterministic LCG for reproducible erasure
    fn erase(vec: &SparseVec, p: f32, rng: &mut u64) -> SparseVec {
        let mut kept = Vec::new();
        for &idx in &vec.indices {
            *rng = rng.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407);
            if (*rng as f32 / u64::MAX as f32) > p {
                kept.push(idx);
            }
        }
        SparseVec { indices: kept }
    }

    #[test]
    fn proof_of_graceful_degradation_monotonicity() {
        let mem = build_synthetic_hierarchy(100_000); // N=100k, beta=4.0
        let target_id = 42;
        let target = mem.store[target_id].clone();

        let erasure_rates = [0.0, 0.5, 0.8, 0.9, 0.95, 0.96, 0.97, 0.98, 0.99, 0.995];
        let mut prev_bits = 24.0;

        for &p in &erasure_rates {
            let mut total_bits = 0.0;
            let trials = 500;
            for t in 0..trials {
                let mut rng = t as u64 + (p * 1000.0) as u64;
                let q = MultiScaleVec {
                    fine: erase(&target.fine, p, &mut rng),
                    med: erase(&target.med, p, &mut rng),
                    coarse: erase(&target.coarse, p, &mut rng),
                };

                let (pid, bits) = mem.complete(&q);
                // Verify correctness of the recovered hierarchical level
                let correct = match (pid, bits) {
                    (Some(id), 24.0) if id == target_id as u32 => true,
                    (Some(id), 16.0) if is_same_subcluster(id as usize, target_id) => true,
                    (Some(id), 8.0) if is_same_category(id as usize, target_id) => true,
                    _ => false,
                };
                if correct { total_bits += bits; }
            }
            let expected_bits = total_bits / trials as f32;

            // THE PROOF: Expected recovered information is strictly monotonic non-increasing.
            assert!(expected_bits <= prev_bits + 0.01, 
                "VIOLATION: Graceful degradation failed at p={}. {} > {}", 
                p, expected_bits, prev_bits);
            prev_bits = expected_bits;
        }
        // Curve shape: 24.0 -> 24.0 -> 16.0 -> 8.0 -> 0.0
    }
}
```

